export { buildWhereConditions } from "./filters";
export { computeFacets } from "./facets";
export { buildOrderBy } from "./sorting";
export { buildCursorPagination } from "./pagination";
export { createDrizzleHandler } from "./handler";
export type { DrizzleHandlerConfig, DrizzleHandlerResult } from "./handler";
export type {
  ColumnMapping,
  DrizzleDB,
  SortDescriptor,
  CursorPaginationParams,
} from "./types";

import type { Column } from "drizzle-orm";
import type { PgDatabase } from "drizzle-orm/pg-core";

/**
 * Maps tableSchema field keys to Drizzle table columns.
 * This is the bridge between your table UI schema and your database.
 *
 * @example
 * const columnMapping = {
 *   level: logs.level,
 *   date: logs.date,
 *   latency: logs.latency,
 *   "timing.dns": logs.timingDns,
 * } satisfies ColumnMapping;
 */
export type ColumnMapping = Record<string, Column>;

export type DrizzleDB = PgDatabase<any, any, any>;

/** Sort descriptor matching the URL state shape. */
export type SortDescriptor = { id: string; desc: boolean } | null;

/** Cursor-based pagination params. */
export type CursorPaginationParams = {
  cursor: Date | number | null;
  direction: "prev" | "next";
  size: number;
  cursorColumn: Column;
};

import type { FacetMetadataSchema } from "@/lib/data-table/types";
import type { TableSchemaDefinition } from "@/lib/table-schema";
import { and, count, sql, type SQL } from "drizzle-orm";
import type { PgTable } from "drizzle-orm/pg-core";
import { computeFacets } from "./facets";
import { buildWhereConditions } from "./filters";
import { buildCursorPagination } from "./pagination";
import { buildOrderBy } from "./sorting";
import type { ColumnMapping, DrizzleDB, SortDescriptor } from "./types";

/**
 * Derive slider, facet, and date keys from a tableSchema definition.
 * Reads `builder._config.filter.type` so no manual key lists are needed.
 */
function deriveKeys(schema: TableSchemaDefinition) {
  const sliderKeys: string[] = [];
  const facetKeys: string[] = [];
  const dateKeys: string[] = [];

  for (const [key, builder] of Object.entries(schema)) {
    const filter = builder._config.filter;
    if (!filter) continue;
    if (filter.type === "slider") {
      sliderKeys.push(key);
      facetKeys.push(key);
    }
    if (filter.type === "checkbox") facetKeys.push(key);
    if (filter.type === "input") facetKeys.push(key);
    if (filter.type === "timerange") dateKeys.push(key);
  }

  return { sliderKeys, facetKeys, dateKeys };
}

type DrizzleHandlerKeys = {
  sliderKeys: string[];
  facetKeys: string[];
  dateKeys: string[];
};

type DrizzleHandlerConfigBase = {
  db: DrizzleDB;
  table: PgTable;
  columnMapping: ColumnMapping;
  cursorColumn: string;
  defaultSize?: number;
};

/**
 * Config with explicit key lists — use when `tableSchema` is in a
 * `"use client"` file and cannot be imported on the server.
 */
export type DrizzleHandlerConfigWithKeys = DrizzleHandlerConfigBase &
  DrizzleHandlerKeys;

/**
 * Config with `tableSchema.definition` — slider/facet/date keys are
 * derived automatically from `builder._config.filter.type`.
 */
export type DrizzleHandlerConfigWithSchema = DrizzleHandlerConfigBase & {
  schema: TableSchemaDefinition;
};

export type DrizzleHandlerConfig =
  | DrizzleHandlerConfigWithKeys
  | DrizzleHandlerConfigWithSchema;

export type DrizzleHandlerResult<TRow = Record<string, unknown>> = {
  data: TRow[];
  facets: Record<string, FacetMetadataSchema>;
  totalRowCount: number;
  filterRowCount: number;
  nextCursor: number | null;
  prevCursor: number | null;
  /** The combined WHERE conditions (all three passes). Useful for chart queries. */
  allConditions: SQL[];
};

function resolveKeys(config: DrizzleHandlerConfig): DrizzleHandlerKeys {
  if ("schema" in config) {
    return deriveKeys(config.schema);
  }
  return {
    sliderKeys: config.sliderKeys,
    facetKeys: config.facetKeys,
    dateKeys: config.dateKeys,
  };
}

/**
 * Create a high-level query handler that encapsulates the three-pass filtering
 * strategy, faceted search, counts, and cursor pagination.
 *
 * Chart data and percentiles are intentionally excluded — handle them in user-land.
 *
 * @example
 * ```ts
 * // Option 1: Derive keys from tableSchema (when importable)
 * const handler = createDrizzleHandler({
 *   db,
 *   table: logs,
 *   schema: tableSchema.definition,
 *   columnMapping,
 *   cursorColumn: "date",
 * });
 *
 * // Option 2: Explicit keys (when tableSchema is "use client")
 * const handler = createDrizzleHandler({
 *   db,
 *   table: logs,
 *   columnMapping,
 *   cursorColumn: "date",
 *   sliderKeys: ["latency", "timing.dns", ...],
 *   facetKeys: ["level", "method", "latency", ...],
 *   dateKeys: ["date"],
 * });
 *
 * const result = await handler.execute(search);
 * ```
 */
export function createDrizzleHandler(config: DrizzleHandlerConfig) {
  const { db, table, columnMapping, cursorColumn, defaultSize = 40 } = config;
  const { sliderKeys, facetKeys, dateKeys } = resolveKeys(config);

  const cursorCol = columnMapping[cursorColumn];
  if (!cursorCol) {
    throw new Error(
      `cursorColumn "${cursorColumn}" not found in columnMapping`,
    );
  }

  return {
    /** Derived keys (exposed for advanced use cases) */
    sliderKeys,
    facetKeys,
    dateKeys,

    async execute(
      search: Record<string, unknown>,
    ): Promise<DrizzleHandlerResult> {
      const size = typeof search.size === "number" ? search.size : defaultSize;
      const sort = (search.sort as SortDescriptor) ?? null;
      const cursor = (search.cursor as Date | number | null) ?? null;
      const direction = (search.direction as "prev" | "next") ?? "next";

      // --- Three-pass filtering strategy ---

      // Pass 1: Date range conditions only
      const dateFilters = Object.fromEntries(
        Object.entries(search).filter(([key]) => dateKeys.includes(key)),
      );
      const dateConditions = buildWhereConditions(columnMapping, dateFilters);

      // Pass 2: Date + non-slider filters (for slider facet bounds)
      const nonSliderFilters = Object.fromEntries(
        Object.entries(search).filter(
          ([key]) => !sliderKeys.includes(key) && !dateKeys.includes(key),
        ),
      );
      const nonSliderConditions = buildWhereConditions(
        columnMapping,
        nonSliderFilters,
      );
      const pass2Conditions = [...dateConditions, ...nonSliderConditions];

      // Pass 3: All conditions including sliders
      const sliderFilters = Object.fromEntries(
        Object.entries(search).filter(([key]) => sliderKeys.includes(key)),
      );
      const sliderConditions = buildWhereConditions(
        columnMapping,
        sliderFilters,
      );
      const allConditions = [...pass2Conditions, ...sliderConditions];

      // --- Facets (parallel) ---
      const [sliderFacets, otherFacets] = await Promise.all([
        computeFacets(db, table, columnMapping, pass2Conditions, sliderKeys, {
          sliderKeys,
        }),
        computeFacets(
          db,
          table,
          columnMapping,
          allConditions,
          facetKeys.filter((k) => !sliderKeys.includes(k)),
        ),
      ]);

      const facets = { ...sliderFacets, ...otherFacets };

      // --- Counts (parallel) ---
      const allWhere =
        allConditions.length > 0 ? and(...allConditions) : undefined;

      const [totalResult, filterResult] = await Promise.all([
        db.select({ total: count() }).from(table),
        db.select({ total: count() }).from(table).where(allWhere),
      ]);

      const totalRowCount = totalResult[0]?.total ?? 0;
      const filterRowCount = filterResult[0]?.total ?? 0;

      // --- Sort + Cursor Pagination ---
      const orderBy = buildOrderBy(columnMapping, sort);

      const {
        cursorCondition,
        orderBy: cursorOrderBy,
        needsReverse,
      } = buildCursorPagination({
        cursor,
        direction,
        size,
        cursorColumn: cursorCol,
      });

      const dataConditions = cursorCondition
        ? [...allConditions, cursorCondition]
        : allConditions;

      const dataWhere =
        dataConditions.length > 0 ? and(...dataConditions) : undefined;

      const orderClauses = orderBy
        ? sql`${cursorOrderBy}, ${orderBy}`
        : cursorOrderBy;

      const rows = await db
        .select()
        .from(table)
        .where(dataWhere)
        .orderBy(orderClauses)
        .limit(size);

      if (needsReverse) {
        rows.reverse();
      }

      // --- Cursors ---
      const lastRow = rows[rows.length - 1];
      const firstRow = rows[0];

      const getCursorValue = (row: Record<string, unknown>): number | null => {
        if (!row) return null;
        const val = row[cursorCol.name];
        if (val instanceof Date) return val.getTime();
        if (typeof val === "number") return val;
        return null;
      };

      const nextCursor = lastRow ? getCursorValue(lastRow) : null;
      const prevCursor = firstRow
        ? getCursorValue(firstRow)
        : new Date().getTime();

      return {
        data: rows,
        facets,
        totalRowCount,
        filterRowCount,
        nextCursor,
        prevCursor,
        allConditions,
      };
    },
  };
}

import type { FacetMetadataSchema } from "@/lib/data-table/types";
import { and, count, max, min, sql, type SQL } from "drizzle-orm";
import type { PgTable } from "drizzle-orm/pg-core";
import type { ColumnMapping, DrizzleDB } from "./types";

/**
 * Compute faceted counts for filter fields via SQL.
 *
 * For each key:
 * - Slider fields: SELECT MIN(col), MAX(col), COUNT(*)
 * - Array columns: unnest + GROUP BY for unique values
 * - Standard columns: GROUP BY for unique values with counts
 *
 * All facet queries run in parallel via Promise.all.
 */
export async function computeFacets(
  db: DrizzleDB,
  table: PgTable,
  mapping: ColumnMapping,
  baseConditions: SQL[],
  facetKeys: string[],
  options?: {
    /** Keys that should return min/max instead of grouped values */
    sliderKeys?: string[];
  },
): Promise<Record<string, FacetMetadataSchema>> {
  const whereCondition =
    baseConditions.length > 0 ? and(...baseConditions) : undefined;
  const sliderKeys = options?.sliderKeys ?? [];

  const queries = facetKeys.map(async (key) => {
    const column = mapping[key];
    if (!column) return [key, null] as const;

    if (sliderKeys.includes(key)) {
      const result = await db
        .select({
          min: min(column),
          max: max(column),
          total: count(),
        })
        .from(table)
        .where(whereCondition);

      const row = result[0];

      return [
        key,
        {
          rows: [],
          total: Number(row?.total ?? 0),
          min: row?.min != null ? Number(row.min) : undefined,
          max: row?.max != null ? Number(row.max) : undefined,
        } satisfies FacetMetadataSchema,
      ] as const;
    }

    // Array columns: unnest + GROUP BY
    if (column.dataType === "array") {
      const raw = await db.execute(
        sql`SELECT val as value, COUNT(*)::int as total
            FROM (
              SELECT unnest(${column}) as val
              FROM ${table}
              ${whereCondition ? sql`WHERE ${whereCondition}` : sql``}
            ) sub
            GROUP BY val
            ORDER BY total DESC`,
      );
      const result: { value: string; total: number }[] = Array.isArray(raw)
        ? raw
        : (raw as { rows: { value: string; total: number }[] }).rows;

      const total = result.reduce((sum, r) => sum + Number(r.total), 0);

      return [
        key,
        {
          rows: result.map((r) => ({
            value: r.value,
            total: Number(r.total),
          })),
          total,
        } satisfies FacetMetadataSchema,
      ] as const;
    }

    // Standard column: GROUP BY
    const raw = await db.execute(
      sql`SELECT ${column} as value, COUNT(*)::int as total
          FROM ${table}
          ${whereCondition ? sql`WHERE ${whereCondition}` : sql``}
          GROUP BY ${column}
          ORDER BY total DESC`,
    );
    const result: { value: string | number | boolean; total: number }[] =
      Array.isArray(raw)
        ? raw
        : (
            raw as {
              rows: { value: string | number | boolean; total: number }[];
            }
          ).rows;

    const total = result.reduce((sum, r) => sum + Number(r.total), 0);

    let minVal: number | undefined;
    let maxVal: number | undefined;
    if (result.length > 0 && typeof result[0].value === "number") {
      minVal = Math.min(...result.map((r) => Number(r.value)));
      maxVal = Math.max(...result.map((r) => Number(r.value)));
    }

    return [
      key,
      {
        rows: result.map((r) => ({
          value: r.value,
          total: Number(r.total),
        })),
        total,
        min: minVal,
        max: maxVal,
      } satisfies FacetMetadataSchema,
    ] as const;
  });

  const results = await Promise.all(queries);
  return Object.fromEntries(results.filter(([, v]) => v !== null));
}

import { endOfDay, startOfDay } from "date-fns";
import {
  and,
  between,
  eq,
  gte,
  ilike,
  inArray,
  lte,
  sql,
  type SQL,
} from "drizzle-orm";
import type { ColumnMapping } from "./types";

/**
 * Build WHERE conditions from filter state and a column mapping.
 *
 * Dispatches by filter value shape:
 * - string → ilike (text search)
 * - number → eq
 * - Date[] → date range (gte/lte or same-day)
 * - number[] → between (slider range) or inArray (checkbox with numbers)
 * - string[] → inArray (checkbox with strings)
 *
 * @param mapping - Maps filter keys to Drizzle columns
 * @param filters - Current filter values from parsed search params
 * @param options - { exclude, only } to skip/limit keys (for three-pass strategy)
 */
export function buildWhereConditions(
  mapping: ColumnMapping,
  filters: Record<string, unknown>,
  options?: { exclude?: string[]; only?: string[] },
): SQL[] {
  const conditions: SQL[] = [];

  for (const [key, value] of Object.entries(filters)) {
    if (value === null || value === undefined) continue;
    if (Array.isArray(value) && value.length === 0) continue;
    if (options?.exclude?.includes(key)) continue;
    if (options?.only && !options.only.includes(key)) continue;

    const column = mapping[key];
    if (!column) continue;

    // String → text search (ilike)
    if (typeof value === "string") {
      conditions.push(ilike(column, `%${value}%`));
      continue;
    }

    // Number → exact match
    if (typeof value === "number") {
      conditions.push(eq(column, value));
      continue;
    }

    // Boolean → exact match
    if (typeof value === "boolean") {
      conditions.push(eq(column, value));
      continue;
    }

    // Array handling
    if (Array.isArray(value)) {
      // Date array → date range
      if (value[0] instanceof Date) {
        const dates = value as Date[];
        if (dates.length === 1) {
          conditions.push(
            and(
              gte(column, startOfDay(dates[0])),
              lte(column, endOfDay(dates[0])),
            )!,
          );
        } else if (dates.length === 2) {
          conditions.push(and(gte(column, dates[0]), lte(column, dates[1]))!);
        }
        continue;
      }

      // Number array → slider range or checkbox
      if (typeof value[0] === "number") {
        const nums = value as number[];
        if (nums.length === 1) {
          conditions.push(eq(column, nums[0]));
        } else if (nums.length === 2) {
          conditions.push(between(column, nums[0], nums[1]));
        } else {
          conditions.push(inArray(column, nums));
        }
        continue;
      }

      // String array → checkbox (inArray) or pg array overlap
      if (typeof value[0] === "string") {
        const strs = value as string[];
        if (column.dataType === "array") {
          conditions.push(
            sql`${column} && ARRAY[${sql.join(
              strs.map((s) => sql`${s}`),
              sql`, `,
            )}]::text[]`,
          );
        } else {
          conditions.push(inArray(column, strs));
        }
        continue;
      }
    }
  }

  return conditions;
}

import { asc, desc, gt, lt, type SQL } from "drizzle-orm";
import type { CursorPaginationParams } from "./types";

/**
 * Build cursor-based pagination conditions and ordering.
 *
 * - direction "next": fetch rows BEFORE cursor (older) → ORDER BY cursorCol DESC
 * - direction "prev": fetch rows AFTER cursor (newer) → ORDER BY cursorCol ASC
 */
export function buildCursorPagination(params: CursorPaginationParams): {
  cursorCondition: SQL | undefined;
  orderBy: SQL;
  needsReverse: boolean;
} {
  const { cursor, direction, cursorColumn } = params;

  const cursorValue =
    cursor instanceof Date
      ? cursor
      : cursor != null
        ? new Date(cursor)
        : new Date();

  if (direction === "prev") {
    return {
      cursorCondition: gt(cursorColumn, cursorValue),
      orderBy: asc(cursorColumn),
      needsReverse: true,
    };
  }

  return {
    cursorCondition: lt(cursorColumn, cursorValue),
    orderBy: desc(cursorColumn),
    needsReverse: false,
  };
}

import { asc, desc, type SQL } from "drizzle-orm";
import type { ColumnMapping, SortDescriptor } from "./types";

/**
 * Build an ORDER BY clause from a sort descriptor.
 * Returns undefined if no sort is specified or the column isn't mapped.
 */
export function buildOrderBy(
  mapping: ColumnMapping,
  sort: SortDescriptor,
): SQL | undefined {
  if (!sort) return undefined;

  const column = mapping[sort.id];
  if (!column) return undefined;

  return sort.desc ? desc(column) : asc(column);
}
